// dropos-responsive-pages.js — node dropos-responsive-pages.js
const fs=require('fs'),path=require('path'),{execSync}=require('child_process');
const files={"frontend/src/app/dashboard/page.tsx":"\"use client\";\nimport { useState, useEffect } from \"react\";\nimport { useQuery } from \"@tanstack/react-query\";\nimport { motion } from \"framer-motion\";\nimport Link from \"next/link\";\nimport {\n  TrendingUp, ShoppingCart, Users, Package,\n  Zap, Sparkles, ChevronRight, AlertCircle,\n  Store, Flame, Activity, ArrowUpRight,\n} from \"lucide-react\";\nimport { useTheme } from \"../../components/layout/DashboardLayout\";\nimport { useAuthStore } from \"../../store/auth.store\";\nimport { api } from \"../../lib/api\";\n\nconst V = { v500: \"#6B35E8\", v400: \"#8B5CF6\", v300: \"#A78BFA\", cyan: \"#06B6D4\" };\n\nexport default function DashboardPage() {\n  const { theme } = useTheme();\n  const { user } = useAuthStore();\n  const isDark = theme === \"dark\";\n  const firstName = user?.name?.split(\" \")[0] || \"there\";\n  const storeId   = user?.stores?.[0]?.id;\n  const [greeting, setGreeting] = useState(\"morning\");\n\n  useEffect(() => {\n    const h = new Date().getHours();\n    setGreeting(h < 12 ? \"morning\" : h < 17 ? \"afternoon\" : \"evening\");\n  }, []);\n\n  const t = {\n    card:   isDark ? \"#181230\" : \"#fff\",\n    border: isDark ? \"rgba(255,255,255,0.06)\" : \"rgba(15,5,32,0.07)\",\n    text:   isDark ? \"#fff\" : \"#0D0918\",\n    muted:  isDark ? \"rgba(255,255,255,0.38)\" : \"rgba(13,9,24,0.45)\",\n    faint:  isDark ? \"rgba(255,255,255,0.04)\" : \"rgba(15,5,32,0.03)\",\n  };\n\n  const { data: analytics } = useQuery({\n    queryKey: [\"dashboard-analytics\", storeId],\n    queryFn:  () => api.get(`/analytics/${storeId}`).then(r => r.data.data),\n    enabled:  !!storeId,\n  });\n\n  const { data: recentOrders } = useQuery({\n    queryKey: [\"dashboard-orders\", storeId],\n    queryFn:  () => api.get(`/orders/${storeId}?limit=5`).then(r => r.data.data?.orders || r.data.data || []),\n    enabled:  !!storeId,\n  });\n\n  const a = analytics || {};\n  const orders: any[] = recentOrders || [];\n\n  const stats = [\n    { label: \"Revenue Today\", value: `₦${((a.todayRevenue || 0)/1000).toFixed(0)}k`, color: V.v400,   icon: TrendingUp,  sub: `${a.todayOrders || 0} orders` },\n    { label: \"Total Orders\",  value: a.totalOrders  || \"0\",                           color: V.cyan,   icon: ShoppingCart, sub: \"All time\" },\n    { label: \"Customers\",     value: a.totalCustomers || \"0\",                          color: \"#10B981\", icon: Users,       sub: \"Total\" },\n    { label: \"Products\",      value: a.totalProducts  || \"0\",                          color: \"#C026D3\", icon: Package,     sub: \"Live\" },\n  ];\n\n  const quickActions = [\n    { label: \"Add Product\", href: \"/dashboard/products\", icon: Package, color: V.v400 },\n    { label: \"View Store\",  href: \"/dashboard/stores\",   icon: Store,   color: V.cyan },\n    { label: \"Flash Sale\",  href: \"/dashboard/flash-sales\", icon: Flame,  color: \"#F59E0B\" },\n    { label: \"Analytics\",  href: \"/dashboard/analytics\", icon: Activity, color: \"#10B981\" },\n  ];\n\n  const insights = [\n    { text: \"Your store is ready. Ask KIRO to set up your first product collection.\", color: V.v400, icon: Sparkles },\n    { text: \"Enable abandoned cart recovery — KIRO recovers up to 15% of lost sales.\", color: \"#10B981\", icon: TrendingUp },\n    { text: \"Add a custom domain to build trust with customers.\", color: \"#F59E0B\", icon: AlertCircle },\n  ];\n\n  return (\n    <div className=\"max-w-7xl mx-auto\">\n      {/* Header */}\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}\n        className=\"flex items-start justify-between gap-4 mb-6\">\n        <div>\n          <h1 className=\"text-xl sm:text-2xl font-black tracking-tight\" style={{ color: t.text }}>\n            Good {greeting}, {firstName} 👋\n          </h1>\n          <p className=\"text-xs sm:text-sm mt-1\" style={{ color: t.muted }}>\n            Here's what's happening with your store today.\n          </p>\n        </div>\n        <Link href=\"/dashboard/kai\" className=\"flex-shrink-0\">\n          <motion.button whileTap={{ scale: 0.97 }}\n            className=\"flex items-center gap-2 px-3 sm:px-5 py-2 sm:py-2.5 rounded-xl text-xs sm:text-sm font-bold text-white\"\n            style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\", boxShadow: \"0 4px 16px rgba(107,53,232,0.35)\" }}>\n            <Zap size={13} /> <span className=\"hidden sm:inline\">Ask</span> KIRO\n          </motion.button>\n        </Link>\n      </motion.div>\n\n      {/* Stats grid — 2 col mobile, 4 col desktop */}\n      <div className=\"grid grid-cols-2 lg:grid-cols-4 gap-3 mb-5\">\n        {stats.map((s, i) => {\n          const Icon = s.icon;\n          return (\n            <motion.div key={s.label} initial={{ opacity: 0, y: 14 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.07 }}\n              className=\"rounded-2xl p-4 relative overflow-hidden\"\n              style={{ background: t.card, border: `1px solid ${t.border}` }}>\n              <div className=\"absolute top-0 left-0 right-0 h-0.5\" style={{ background: `linear-gradient(90deg,transparent,${s.color}60,transparent)` }} />\n              <div className=\"w-8 h-8 rounded-xl flex items-center justify-center mb-3\" style={{ background: `${s.color}15` }}>\n                <Icon size={15} style={{ color: s.color }} />\n              </div>\n              <p className=\"text-xl sm:text-2xl font-black mb-0.5\" style={{ color: t.text }}>{s.value}</p>\n              <p className=\"text-xs font-semibold\" style={{ color: t.text }}>{s.label}</p>\n              {s.sub && <p className=\"text-[10px] mt-0.5\" style={{ color: t.muted }}>{s.sub}</p>}\n            </motion.div>\n          );\n        })}\n      </div>\n\n      {/* Main 2-col — stacks on mobile */}\n      <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-4\">\n\n        {/* Recent orders — takes 2/3 on desktop */}\n        <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.25 }}\n          className=\"lg:col-span-2 rounded-2xl overflow-hidden\"\n          style={{ background: t.card, border: `1px solid ${t.border}` }}>\n          <div className=\"flex items-center justify-between px-4 sm:px-5 py-4\" style={{ borderBottom: `1px solid ${t.border}` }}>\n            <span className=\"text-sm font-bold\" style={{ color: t.text }}>Recent Orders</span>\n            <Link href=\"/dashboard/orders\" className=\"text-xs font-semibold\" style={{ color: V.v300 }}>\n              See all <ArrowUpRight size={10} className=\"inline\" />\n            </Link>\n          </div>\n\n          {orders.length === 0 ? (\n            <div className=\"flex flex-col items-center justify-center py-16 px-6 text-center\">\n              <div className=\"w-12 h-12 rounded-2xl flex items-center justify-center mb-4\" style={{ background: t.faint }}>\n                <ShoppingCart size={20} style={{ color: t.muted }} />\n              </div>\n              <p className=\"text-sm font-semibold mb-1\" style={{ color: t.muted }}>No orders yet</p>\n              <p className=\"text-xs mb-4\" style={{ color: t.muted, opacity: 0.7 }}>Your first order will appear here</p>\n              <Link href=\"/dashboard/kai\">\n                <div className=\"flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold cursor-pointer\"\n                  style={{ background: \"rgba(107,53,232,0.1)\", color: V.v300 }}>\n                  <Zap size={11} /> Ask KIRO to get first sales\n                </div>\n              </Link>\n            </div>\n          ) : (\n            <div className=\"divide-y\" style={{ borderColor: t.border }}>\n              {orders.slice(0, 5).map((order: any) => (\n                <Link href=\"/dashboard/orders\" key={order.id}\n                  className=\"flex items-center gap-3 px-4 sm:px-5 py-3 hover:opacity-80 transition-opacity\">\n                  <div className=\"w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0 text-white text-xs font-black\"\n                    style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n                    {(order.customerName || order.customer?.name || \"?\")[0]}\n                  </div>\n                  <div className=\"flex-1 min-w-0\">\n                    <p className=\"text-sm font-semibold truncate\" style={{ color: t.text }}>{order.customerName || order.customer?.name || \"Customer\"}</p>\n                    <p className=\"text-xs\" style={{ color: t.muted }}>{(order.items || []).length} item{(order.items || []).length !== 1 ? \"s\" : \"\"}</p>\n                  </div>\n                  <p className=\"text-sm font-bold flex-shrink-0\" style={{ color: \"#10B981\" }}>₦{Number(order.total || 0).toLocaleString()}</p>\n                </Link>\n              ))}\n            </div>\n          )}\n        </motion.div>\n\n        {/* Right col */}\n        <div className=\"flex flex-col gap-4\">\n          {/* KIRO insights */}\n          <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.32 }}\n            className=\"rounded-2xl p-4\"\n            style={{ background: isDark ? \"linear-gradient(135deg,rgba(107,53,232,0.1),rgba(91,33,182,0.05))\" : \"rgba(107,53,232,0.04)\", border: \"1px solid rgba(107,53,232,0.2)\" }}>\n            <div className=\"flex items-center gap-2 mb-4\">\n              <div className=\"w-7 h-7 rounded-lg flex items-center justify-center\" style={{ background: \"linear-gradient(145deg,#6B35E8,#1A0D3D)\" }}>\n                <Zap size={12} color=\"white\" />\n              </div>\n              <span className=\"text-sm font-bold\" style={{ color: isDark ? \"#C4B5FD\" : \"#3D1C8A\" }}>KIRO Insights</span>\n            </div>\n            <div className=\"space-y-2 mb-4\">\n              {insights.map((ins, i) => {\n                const Icon = ins.icon;\n                return (\n                  <div key={i} className=\"flex items-start gap-2.5 p-2.5 rounded-xl\"\n                    style={{ background: `${ins.color}08`, border: `1px solid ${ins.color}20` }}>\n                    <div className=\"w-5 h-5 rounded-md flex items-center justify-center flex-shrink-0 mt-0.5\" style={{ background: `${ins.color}20` }}>\n                      <Icon size={10} style={{ color: ins.color }} />\n                    </div>\n                    <p className=\"text-xs leading-relaxed\" style={{ color: t.muted }}>{ins.text}</p>\n                  </div>\n                );\n              })}\n            </div>\n            <Link href=\"/dashboard/kai\">\n              <button className=\"w-full flex items-center justify-center gap-2 py-2.5 rounded-xl text-xs font-bold text-white\"\n                style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n                <Zap size={11} /> Chat with KIRO\n              </button>\n            </Link>\n          </motion.div>\n\n          {/* Quick actions */}\n          <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.38 }}\n            className=\"rounded-2xl p-4\"\n            style={{ background: t.card, border: `1px solid ${t.border}` }}>\n            <p className=\"text-sm font-bold mb-3\" style={{ color: t.text }}>Quick Actions</p>\n            <div className=\"grid grid-cols-2 gap-2\">\n              {quickActions.map(a => {\n                const Icon = a.icon;\n                return (\n                  <Link href={a.href} key={a.label}>\n                    <motion.div whileTap={{ scale: 0.96 }}\n                      className=\"flex flex-col items-center gap-2 p-3 rounded-xl cursor-pointer\"\n                      style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n                      <div className=\"w-8 h-8 rounded-xl flex items-center justify-center\" style={{ background: `${a.color}15` }}>\n                        <Icon size={15} style={{ color: a.color }} />\n                      </div>\n                      <span className=\"text-xs font-medium text-center\" style={{ color: t.muted }}>{a.label}</span>\n                    </motion.div>\n                  </Link>\n                );\n              })}\n            </div>\n          </motion.div>\n        </div>\n      </div>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/settings/page.tsx":"\"use client\";\nimport { useState } from \"react\";\nimport { motion } from \"framer-motion\";\nimport { useTheme, useToast, useConfirm } from \"../../../components/layout/DashboardLayout\";\nimport { useAuthStore } from \"../../../store/auth.store\";\nimport { api } from \"../../../lib/api\";\nimport { User, Bell, Shield, Palette, Globe, Trash2, Eye, EyeOff, ChevronRight, Camera, Sun, Moon, Check } from \"lucide-react\";\n\nconst V = { v500: \"#6B35E8\", v400: \"#8B5CF6\", v300: \"#A78BFA\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\", input: \"rgba(255,255,255,0.05)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\", input: \"rgba(15,5,32,0.04)\" },\n};\n\nconst SECTIONS = [\n  { id: \"profile\",       label: \"Profile\",      icon: User    },\n  { id: \"notifications\", label: \"Alerts\",       icon: Bell    },\n  { id: \"security\",      label: \"Security\",     icon: Shield  },\n  { id: \"appearance\",    label: \"Appearance\",   icon: Palette },\n  { id: \"danger\",        label: \"Danger Zone\",  icon: Trash2  },\n];\n\nfunction SettingRow({ label, desc, children, t }: any) {\n  return (\n    <div className=\"flex items-center justify-between py-4 gap-4\" style={{ borderBottom: `1px solid ${t.border}` }}>\n      <div className=\"flex-1 min-w-0\">\n        <p className=\"text-sm font-semibold\" style={{ color: t.text }}>{label}</p>\n        {desc && <p className=\"text-xs mt-0.5\" style={{ color: t.muted }}>{desc}</p>}\n      </div>\n      <div className=\"flex-shrink-0\">{children}</div>\n    </div>\n  );\n}\n\nfunction Toggle({ value, onChange }: { value: boolean; onChange: (v: boolean) => void }) {\n  return (\n    <button onClick={() => onChange(!value)}\n      className=\"relative flex-shrink-0 transition-all\"\n      style={{ width: 44, height: 24, borderRadius: 12, border: \"none\", cursor: \"pointer\", background: value ? V.v500 : \"rgba(128,128,128,0.2)\" }}>\n      <div className=\"absolute top-0.5 w-5 h-5 rounded-full bg-white transition-all shadow-sm\" style={{ left: value ? 22 : 2 }} />\n    </button>\n  );\n}\n\nfunction TextInput({ label, value, onChange, type = \"text\", placeholder, t, disabled }: any) {\n  const [show, setShow] = useState(false);\n  return (\n    <div>\n      <label className=\"block text-xs font-semibold mb-1.5\" style={{ color: t.muted }}>{label}</label>\n      <div className=\"relative\">\n        <input\n          type={type === \"password\" ? (show ? \"text\" : \"password\") : type}\n          value={value} onChange={e => onChange(e.target.value)}\n          placeholder={placeholder} disabled={disabled}\n          className=\"w-full px-4 py-3 rounded-xl text-sm outline-none\"\n          style={{ border: `1px solid ${t.border}`, background: disabled ? t.faint : t.input, color: t.text, fontFamily: \"inherit\", paddingRight: type === \"password\" ? 44 : 16, opacity: disabled ? 0.6 : 1 }}\n        />\n        {type === \"password\" && (\n          <button type=\"button\" onClick={() => setShow(!show)} className=\"absolute right-3 top-1/2 -translate-y-1/2\" style={{ border: \"none\", background: \"none\", cursor: \"pointer\", color: t.muted }}>\n            {show ? <EyeOff size={14} /> : <Eye size={14} />}\n          </button>\n        )}\n      </div>\n    </div>\n  );\n}\n\nexport default function SettingsPage() {\n  const { theme, toggle: toggleTheme } = useTheme();\n  const { show } = useToast();\n  const { confirm } = useConfirm();\n  const { user } = useAuthStore();\n  const isDark = theme === \"dark\";\n  const t = isDark ? T.dark : T.light;\n\n  const [activeSection, setActiveSection] = useState(\"profile\");\n  const [saving, setSaving] = useState(false);\n  const [name, setName]   = useState(user?.name || \"\");\n  const [email, setEmail] = useState(user?.email || \"\");\n  const [currentPw, setCurrentPw] = useState(\"\");\n  const [newPw, setNewPw]         = useState(\"\");\n  const [notifs, setNotifs] = useState({ orders: true, marketing: false, security: true, updates: true, kiro: true });\n\n  const handleSaveProfile = async () => {\n    setSaving(true);\n    try { await api.put(\"/auth/profile\", { name, email }); show(\"Profile saved\", \"success\"); }\n    catch { show(\"Saved locally (backend offline)\", \"info\"); }\n    finally { setSaving(false); }\n  };\n\n  const handleChangePassword = async () => {\n    if (!currentPw || !newPw) { show(\"Fill in both fields\", \"error\"); return; }\n    try { await api.put(\"/auth/password\", { currentPassword: currentPw, newPassword: newPw }); show(\"Password updated\", \"success\"); setCurrentPw(\"\"); setNewPw(\"\"); }\n    catch (e: any) { show(e.response?.data?.message || \"Failed\", \"error\"); }\n  };\n\n  const handleDelete = async () => {\n    const ok = await confirm({ title: \"Delete your account?\", message: \"This permanently deletes your account and all store data. Cannot be undone.\", confirmText: \"Yes, delete everything\", cancelText: \"Keep my account\", variant: \"danger\" });\n    if (ok) show(\"Account deletion requested\", \"info\");\n  };\n\n  return (\n    <div className=\"max-w-4xl mx-auto\">\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }} className=\"mb-6\">\n        <h1 className=\"text-xl sm:text-2xl font-black tracking-tight\" style={{ color: t.text }}>Settings</h1>\n        <p className=\"text-xs sm:text-sm mt-1\" style={{ color: t.muted }}>Manage your account and preferences</p>\n      </motion.div>\n\n      <div className=\"flex flex-col sm:flex-row gap-4\">\n        {/* Section sidebar — horizontal scroll on mobile, vertical on desktop */}\n        <div className=\"sm:w-44 flex-shrink-0\">\n          <div className=\"flex sm:flex-col gap-1 overflow-x-auto pb-1 sm:pb-0\" style={{ scrollbarWidth: \"none\" }}>\n            {SECTIONS.map(s => {\n              const Icon = s.icon;\n              const active = activeSection === s.id;\n              return (\n                <button key={s.id} onClick={() => setActiveSection(s.id)}\n                  className=\"flex items-center gap-2.5 px-3 py-2.5 rounded-xl text-left transition-all whitespace-nowrap sm:whitespace-normal flex-shrink-0 sm:flex-shrink w-auto sm:w-full\"\n                  style={{ background: active ? \"rgba(107,53,232,0.1)\" : \"transparent\", border: `1px solid ${active ? \"rgba(107,53,232,0.25)\" : \"transparent\"}`, color: active ? V.v300 : t.muted }}>\n                  <Icon size={14} />\n                  <span className=\"text-xs font-semibold\">{s.label}</span>\n                </button>\n              );\n            })}\n          </div>\n        </div>\n\n        {/* Content */}\n        <div className=\"flex-1 min-w-0\">\n          <motion.div key={activeSection} initial={{ opacity: 0, x: 8 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.15 }}\n            className=\"rounded-2xl p-4 sm:p-6\" style={{ background: t.card, border: `1px solid ${t.border}` }}>\n\n            {activeSection === \"profile\" && (\n              <div className=\"space-y-4\">\n                <h2 className=\"text-sm font-bold mb-4\" style={{ color: t.text }}>Profile</h2>\n                {/* Avatar */}\n                <div className=\"flex items-center gap-4 mb-2\">\n                  <div className=\"relative\">\n                    <div className=\"w-16 h-16 rounded-2xl flex items-center justify-center text-2xl font-black text-white\" style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n                      {name?.[0]?.toUpperCase() || \"U\"}\n                    </div>\n                    <button className=\"absolute -bottom-1 -right-1 w-6 h-6 rounded-full flex items-center justify-center text-white\" style={{ background: V.v500 }}>\n                      <Camera size={10} />\n                    </button>\n                  </div>\n                  <div>\n                    <p className=\"text-sm font-semibold\" style={{ color: t.text }}>{name || \"Your Name\"}</p>\n                    <p className=\"text-xs\" style={{ color: t.muted }}>{email}</p>\n                  </div>\n                </div>\n                <TextInput label=\"Full Name\" value={name} onChange={setName} placeholder=\"Your name\" t={t} />\n                <TextInput label=\"Email\" value={email} onChange={setEmail} type=\"email\" placeholder=\"you@example.com\" t={t} />\n                <button onClick={handleSaveProfile} disabled={saving}\n                  className=\"w-full sm:w-auto px-6 py-2.5 rounded-xl text-sm font-bold text-white flex items-center justify-center gap-2 disabled:opacity-60\"\n                  style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n                  {saving ? \"Saving...\" : \"Save Profile\"}\n                </button>\n              </div>\n            )}\n\n            {activeSection === \"notifications\" && (\n              <div>\n                <h2 className=\"text-sm font-bold mb-1\" style={{ color: t.text }}>Notification Preferences</h2>\n                <p className=\"text-xs mb-4\" style={{ color: t.muted }}>Choose what you want to be notified about</p>\n                {[\n                  { key: \"orders\",    label: \"New Orders\",          desc: \"Get notified when a customer places an order\" },\n                  { key: \"kiro\",      label: \"KIRO Alerts\",         desc: \"Morning briefs, opportunities, and urgent alerts\" },\n                  { key: \"security\",  label: \"Security Alerts\",     desc: \"Login attempts and account security\" },\n                  { key: \"marketing\", label: \"Marketing Tips\",      desc: \"Product ideas and growth suggestions\" },\n                  { key: \"updates\",   label: \"Platform Updates\",    desc: \"New features and improvements\" },\n                ].map(n => (\n                  <SettingRow key={n.key} label={n.label} desc={n.desc} t={t}>\n                    <Toggle value={notifs[n.key as keyof typeof notifs]} onChange={v => setNotifs(p => ({ ...p, [n.key]: v }))} />\n                  </SettingRow>\n                ))}\n              </div>\n            )}\n\n            {activeSection === \"security\" && (\n              <div className=\"space-y-4\">\n                <h2 className=\"text-sm font-bold mb-4\" style={{ color: t.text }}>Security</h2>\n                <TextInput label=\"Current Password\" value={currentPw} onChange={setCurrentPw} type=\"password\" placeholder=\"••••••••\" t={t} />\n                <TextInput label=\"New Password\" value={newPw} onChange={setNewPw} type=\"password\" placeholder=\"Min 8 characters\" t={t} />\n                <button onClick={handleChangePassword}\n                  className=\"w-full sm:w-auto px-6 py-2.5 rounded-xl text-sm font-bold text-white\"\n                  style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n                  Update Password\n                </button>\n                <div className=\"pt-4\" style={{ borderTop: `1px solid ${t.border}` }}>\n                  <SettingRow label=\"Two-Factor Authentication\" desc=\"Add an extra layer of security to your account\" t={t}>\n                    <button className=\"text-xs font-semibold px-3 py-1.5 rounded-lg\" style={{ border: `1px solid ${t.border}`, color: t.muted }}>Enable</button>\n                  </SettingRow>\n                </div>\n              </div>\n            )}\n\n            {activeSection === \"appearance\" && (\n              <div>\n                <h2 className=\"text-sm font-bold mb-4\" style={{ color: t.text }}>Appearance</h2>\n                <SettingRow label=\"Theme\" desc=\"Choose how the dashboard looks\" t={t}>\n                  <div className=\"flex gap-2\">\n                    {[{ mode: \"dark\", icon: Moon, label: \"Dark\" }, { mode: \"light\", icon: Sun, label: \"Light\" }].map(opt => {\n                      const Icon = opt.icon;\n                      const active = theme === opt.mode;\n                      return (\n                        <button key={opt.mode} onClick={toggleTheme}\n                          className=\"flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold transition-all\"\n                          style={{ background: active ? V.v500 : t.faint, color: active ? \"#fff\" : t.muted, border: `1px solid ${active ? V.v500 : t.border}` }}>\n                          <Icon size={12} /> {opt.label}\n                          {active && <Check size={11} />}\n                        </button>\n                      );\n                    })}\n                  </div>\n                </SettingRow>\n              </div>\n            )}\n\n            {activeSection === \"danger\" && (\n              <div>\n                <h2 className=\"text-sm font-bold mb-1 text-red-400\">Danger Zone</h2>\n                <p className=\"text-xs mb-6\" style={{ color: t.muted }}>These actions cannot be undone. Be very careful.</p>\n                <div className=\"p-4 rounded-2xl\" style={{ border: \"1px solid rgba(239,68,68,0.25)\", background: \"rgba(239,68,68,0.05)\" }}>\n                  <p className=\"text-sm font-semibold text-red-400 mb-1\">Delete Account</p>\n                  <p className=\"text-xs mb-4\" style={{ color: t.muted }}>Permanently delete your account and all store data including products, orders, and customer information.</p>\n                  <button onClick={handleDelete} className=\"px-4 py-2 rounded-xl text-xs font-bold text-white\" style={{ background: \"#EF4444\" }}>\n                    Delete My Account\n                  </button>\n                </div>\n              </div>\n            )}\n\n          </motion.div>\n        </div>\n      </div>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/products/page.tsx":"\"use client\";\nimport { useState } from \"react\";\nimport { useQuery, useMutation, useQueryClient } from \"@tanstack/react-query\";\nimport { motion, AnimatePresence } from \"framer-motion\";\nimport { useTheme } from \"../../../components/layout/DashboardLayout\";\nimport { useAuthStore } from \"../../../store/auth.store\";\nimport { api } from \"../../../lib/api\";\nimport { Package, Plus, Search, Edit2, Trash2, Zap, Upload, X, AlertCircle, Loader2, Image as ImageIcon } from \"lucide-react\";\nimport toast from \"react-hot-toast\";\nimport Link from \"next/link\";\n\nconst V = { v500: \"#6B35E8\", v400: \"#8B5CF6\", v300: \"#A78BFA\", cyan: \"#06B6D4\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\" },\n};\n\nconst STATUS_COLORS: Record<string, { color: string; bg: string }> = {\n  ACTIVE:   { color: \"#10B981\", bg: \"rgba(16,185,129,0.12)\"  },\n  DRAFT:    { color: \"#F59E0B\", bg: \"rgba(245,158,11,0.12)\"  },\n  ARCHIVED: { color: \"#6B7280\", bg: \"rgba(107,114,128,0.12)\" },\n};\n\nfunction fmt(n: number) {\n  return new Intl.NumberFormat(\"en\", { style: \"currency\", currency: \"NGN\", maximumFractionDigits: 0 }).format(n || 0);\n}\n\nfunction ProductModal({ storeId, product, onClose, t, isDark }: any) {\n  const qc = useQueryClient();\n  const isEdit = !!product;\n  const [form, setForm] = useState({\n    name: product?.name || \"\", description: product?.description || \"\",\n    price: product?.price?.toString() || \"\", comparePrice: product?.comparePrice?.toString() || \"\",\n    inventory: product?.inventory?.toString() || \"0\", category: product?.category || \"\",\n    status: product?.status || \"ACTIVE\",\n  });\n\n  const inp = { padding: \"10px 14px\", borderRadius: 10, border: `1px solid ${t.border}`, background: isDark ? \"rgba(255,255,255,0.04)\" : \"#f9fafb\", color: t.text, fontSize: 13, outline: \"none\", width: \"100%\", fontFamily: \"inherit\" } as any;\n\n  const mut = useMutation({\n    mutationFn: async () => {\n      const payload = { name: form.name, description: form.description, price: parseFloat(form.price), comparePrice: form.comparePrice ? parseFloat(form.comparePrice) : null, inventory: parseInt(form.inventory), category: form.category, status: form.status };\n      if (isEdit) return api.put(`/products/${storeId}/${product.id}`, payload);\n      return api.post(`/products/${storeId}`, payload);\n    },\n    onSuccess: () => { toast.success(isEdit ? \"Product updated\" : \"Product created\"); qc.invalidateQueries({ queryKey: [\"products\"] }); onClose(); },\n    onError: (e: any) => toast.error(e.response?.data?.message || \"Failed\"),\n  });\n\n  return (\n    <div className=\"fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4\"\n      style={{ background: \"rgba(0,0,0,0.65)\", backdropFilter: \"blur(8px)\" }}\n      onClick={e => e.target === e.currentTarget && onClose()}>\n      <motion.div initial={{ opacity: 0, y: 40 }} animate={{ opacity: 1, y: 0 }}\n        className=\"w-full sm:max-w-lg rounded-t-3xl sm:rounded-3xl overflow-hidden\"\n        style={{ background: isDark ? \"#181230\" : \"#fff\", border: `1px solid ${t.border}`, maxHeight: \"90vh\" }}>\n        <div className=\"flex items-center justify-between px-5 py-4\" style={{ borderBottom: `1px solid ${t.border}` }}>\n          {/* Drag handle on mobile */}\n          <div className=\"sm:hidden absolute top-3 left-1/2 -translate-x-1/2 w-10 h-1 rounded-full\" style={{ background: t.border }} />\n          <h2 className=\"font-black text-base\" style={{ color: t.text }}>{isEdit ? \"Edit Product\" : \"Add Product\"}</h2>\n          <button onClick={onClose} style={{ color: t.muted }}><X size={18} /></button>\n        </div>\n        <div className=\"p-5 space-y-3 overflow-y-auto\" style={{ maxHeight: \"70vh\" }}>\n          <div>\n            <label className=\"block text-xs font-semibold mb-1.5\" style={{ color: t.muted }}>Product Name *</label>\n            <input style={inp} value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder=\"e.g. Premium Hair Bundle\" />\n          </div>\n          <div>\n            <label className=\"block text-xs font-semibold mb-1.5\" style={{ color: t.muted }}>Description</label>\n            <textarea style={{ ...inp, resize: \"none\" } as any} rows={3} value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} placeholder=\"Describe your product...\" />\n          </div>\n          <div className=\"grid grid-cols-2 gap-3\">\n            <div>\n              <label className=\"block text-xs font-semibold mb-1.5\" style={{ color: t.muted }}>Price (₦) *</label>\n              <input style={inp} type=\"number\" value={form.price} onChange={e => setForm(f => ({ ...f, price: e.target.value }))} placeholder=\"25000\" />\n            </div>\n            <div>\n              <label className=\"block text-xs font-semibold mb-1.5\" style={{ color: t.muted }}>Compare At (₦)</label>\n              <input style={inp} type=\"number\" value={form.comparePrice} onChange={e => setForm(f => ({ ...f, comparePrice: e.target.value }))} placeholder=\"35000\" />\n            </div>\n          </div>\n          <div className=\"grid grid-cols-2 gap-3\">\n            <div>\n              <label className=\"block text-xs font-semibold mb-1.5\" style={{ color: t.muted }}>Stock</label>\n              <input style={inp} type=\"number\" value={form.inventory} onChange={e => setForm(f => ({ ...f, inventory: e.target.value }))} placeholder=\"0\" />\n            </div>\n            <div>\n              <label className=\"block text-xs font-semibold mb-1.5\" style={{ color: t.muted }}>Category</label>\n              <input style={inp} value={form.category} onChange={e => setForm(f => ({ ...f, category: e.target.value }))} placeholder=\"e.g. Beauty\" />\n            </div>\n          </div>\n          <div>\n            <label className=\"block text-xs font-semibold mb-1.5\" style={{ color: t.muted }}>Status</label>\n            <select style={{ ...inp, cursor: \"pointer\" } as any} value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))}>\n              <option value=\"ACTIVE\">Active — visible in store</option>\n              <option value=\"DRAFT\">Draft — hidden from store</option>\n              <option value=\"ARCHIVED\">Archived</option>\n            </select>\n          </div>\n        </div>\n        <div className=\"flex gap-3 px-5 py-4\" style={{ borderTop: `1px solid ${t.border}` }}>\n          <button onClick={onClose} className=\"flex-1 py-3 rounded-xl text-sm font-semibold\" style={{ border: `1px solid ${t.border}`, color: t.muted }}>Cancel</button>\n          <button onClick={() => mut.mutate()} disabled={!form.name || !form.price || mut.isPending}\n            className=\"flex-[2] py-3 rounded-xl text-sm font-bold text-white flex items-center justify-center gap-2 disabled:opacity-50\"\n            style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n            {mut.isPending ? <><Loader2 size={14} className=\"animate-spin\" /> Saving…</> : isEdit ? \"Save Changes\" : \"Add Product\"}\n          </button>\n        </div>\n      </motion.div>\n    </div>\n  );\n}\n\nexport default function ProductsPage() {\n  const { theme } = useTheme();\n  const isDark = theme === \"dark\";\n  const t = isDark ? T.dark : T.light;\n  const storeId = useAuthStore(s => s.user?.stores?.[0]?.id);\n  const qc = useQueryClient();\n\n  const [search, setSearch]   = useState(\"\");\n  const [filter, setFilter]   = useState(\"All\");\n  const [showModal, setShowModal] = useState(false);\n  const [editing, setEditing] = useState<any>(null);\n\n  const { data, isLoading } = useQuery({\n    queryKey: [\"products\", storeId],\n    queryFn: () => api.get(`/products/${storeId}`).then(r => r.data.data),\n    enabled: !!storeId,\n  });\n\n  const deleteMut = useMutation({\n    mutationFn: (id: string) => api.delete(`/products/${storeId}/${id}`),\n    onSuccess: () => { toast.success(\"Product deleted\"); qc.invalidateQueries({ queryKey: [\"products\"] }); },\n  });\n\n  const products: any[] = data || [];\n  const filtered = products.filter(p =>\n    (!search || p.name?.toLowerCase().includes(search.toLowerCase())) &&\n    (filter === \"All\" ? true : filter === \"Active\" ? p.status === \"ACTIVE\" : filter === \"Draft\" ? p.status === \"DRAFT\" : p.inventory === 0)\n  );\n\n  const openAdd  = () => { setEditing(null); setShowModal(true); };\n  const openEdit = (p: any) => { setEditing(p); setShowModal(true); };\n\n  return (\n    <div className=\"max-w-7xl mx-auto\">\n      {/* Header */}\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}\n        className=\"flex items-start justify-between gap-3 mb-5\">\n        <div>\n          <h1 className=\"text-xl sm:text-2xl font-black tracking-tight\" style={{ color: t.text }}>Products</h1>\n          <p className=\"text-xs sm:text-sm mt-1\" style={{ color: t.muted }}>{products.length} product{products.length !== 1 ? \"s\" : \"\"}</p>\n        </div>\n        <div className=\"flex gap-2 flex-shrink-0\">\n          <Link href=\"/dashboard/import\">\n            <button className=\"flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold\" style={{ border: `1px solid ${t.border}`, color: t.muted }}>\n              <Upload size={12} /> <span className=\"hidden sm:inline\">Import</span>\n            </button>\n          </Link>\n          <button onClick={openAdd}\n            className=\"flex items-center gap-1.5 px-3 py-2.5 rounded-xl text-xs sm:text-sm font-bold text-white\"\n            style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n            <Plus size={14} /> <span className=\"hidden sm:inline\">Add Product</span><span className=\"sm:hidden\">Add</span>\n          </button>\n        </div>\n      </motion.div>\n\n      {/* Filters + search */}\n      <div className=\"flex items-center gap-2 mb-4 overflow-x-auto pb-1\" style={{ scrollbarWidth: \"none\" }}>\n        <div className=\"flex items-center gap-2 px-3 py-2 rounded-xl flex-shrink-0\" style={{ background: t.card, border: `1px solid ${t.border}` }}>\n          <Search size={12} style={{ color: t.muted }} />\n          <input value={search} onChange={e => setSearch(e.target.value)} placeholder=\"Search products...\"\n            className=\"bg-transparent border-none outline-none text-xs w-28 sm:w-40\"\n            style={{ color: t.text, fontFamily: \"inherit\" }} />\n        </div>\n        {[\"All\", \"Active\", \"Draft\", \"Out of Stock\"].map(f => (\n          <button key={f} onClick={() => setFilter(f)}\n            className=\"px-3 py-2 rounded-xl text-xs font-semibold whitespace-nowrap flex-shrink-0\"\n            style={{ background: filter === f ? V.v500 : t.card, color: filter === f ? \"#fff\" : t.muted, border: `1px solid ${filter === f ? V.v500 : t.border}` }}>\n            {f}\n          </button>\n        ))}\n      </div>\n\n      {/* Products — card grid */}\n      {isLoading ? (\n        <div className=\"grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-3\">\n          {Array.from({ length: 8 }).map((_, i) => (\n            <div key={i} className=\"rounded-2xl overflow-hidden animate-pulse\" style={{ background: t.card }}>\n              <div className=\"aspect-square\" style={{ background: t.faint }} />\n              <div className=\"p-3 space-y-2\">\n                <div className=\"h-3 rounded-full w-3/4\" style={{ background: t.faint }} />\n                <div className=\"h-3 rounded-full w-1/2\" style={{ background: t.faint }} />\n              </div>\n            </div>\n          ))}\n        </div>\n      ) : filtered.length === 0 ? (\n        <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }}\n          className=\"rounded-2xl flex flex-col items-center justify-center py-20 text-center\"\n          style={{ background: t.card, border: `1px solid ${t.border}` }}>\n          <Package size={40} style={{ color: t.muted, opacity: 0.3, marginBottom: 16 }} />\n          <h3 className=\"font-bold text-sm mb-2\" style={{ color: t.text }}>{search ? \"No products found\" : \"No products yet\"}</h3>\n          <p className=\"text-xs mb-5\" style={{ color: t.muted, maxWidth: 280, lineHeight: 1.6 }}>\n            {search ? \"Try a different search\" : \"Add your first product or use KIRO to import products from AliExpress in seconds.\"}\n          </p>\n          <div className=\"flex gap-2\">\n            <button onClick={openAdd} className=\"flex items-center gap-1.5 px-4 py-2 rounded-xl text-xs font-bold text-white\" style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n              <Plus size={12} /> Add Product\n            </button>\n            <Link href=\"/dashboard/kai\">\n              <button className=\"flex items-center gap-1.5 px-4 py-2 rounded-xl text-xs font-semibold\" style={{ border: `1px solid ${t.border}`, color: t.muted }}>\n                <Zap size={12} /> Ask KIRO\n              </button>\n            </Link>\n          </div>\n        </motion.div>\n      ) : (\n        <div className=\"grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-3\">\n          {filtered.map((p, i) => {\n            const st = STATUS_COLORS[p.status] || STATUS_COLORS.DRAFT;\n            const img = p.images?.[0];\n            return (\n              <motion.div key={p.id} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.04 }}\n                className=\"group rounded-2xl overflow-hidden flex flex-col\"\n                style={{ background: t.card, border: `1px solid ${t.border}` }}>\n                {/* Image */}\n                <div className=\"relative aspect-square overflow-hidden\" style={{ background: t.faint }}>\n                  {img\n                    ? <img src={img} alt={p.name} className=\"w-full h-full object-cover group-hover:scale-105 transition-transform duration-500\" />\n                    : <div className=\"w-full h-full flex items-center justify-center\"><Package size={28} style={{ color: t.muted, opacity: 0.4 }} /></div>\n                  }\n                  {/* Actions overlay */}\n                  <div className=\"absolute inset-0 flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity\" style={{ background: \"rgba(0,0,0,0.4)\" }}>\n                    <button onClick={() => openEdit(p)} className=\"w-8 h-8 rounded-xl flex items-center justify-center text-white\" style={{ background: \"rgba(255,255,255,0.15)\" }}>\n                      <Edit2 size={13} />\n                    </button>\n                    <button onClick={() => deleteMut.mutate(p.id)} className=\"w-8 h-8 rounded-xl flex items-center justify-center text-white\" style={{ background: \"rgba(239,68,68,0.5)\" }}>\n                      <Trash2 size={13} />\n                    </button>\n                  </div>\n                  <span className=\"absolute top-2 left-2 text-[10px] font-bold px-2 py-0.5 rounded-full\" style={{ background: st.bg, color: st.color }}>{p.status}</span>\n                </div>\n                {/* Info */}\n                <div className=\"p-3 flex-1 flex flex-col\">\n                  <p className=\"text-xs font-semibold line-clamp-2 flex-1 mb-2\" style={{ color: t.text }}>{p.name}</p>\n                  <div className=\"flex items-center justify-between\">\n                    <p className=\"text-sm font-black\" style={{ color: t.text }}>{fmt(p.price)}</p>\n                    <p className=\"text-[10px]\" style={{ color: p.inventory === 0 ? \"#EF4444\" : t.muted }}>\n                      {p.inventory === 0 ? \"Out\" : `${p.inventory} left`}\n                    </p>\n                  </div>\n                </div>\n              </motion.div>\n            );\n          })}\n        </div>\n      )}\n\n      <AnimatePresence>\n        {showModal && <ProductModal storeId={storeId} product={editing} onClose={() => { setShowModal(false); setEditing(null); }} t={t} isDark={isDark} />}\n      </AnimatePresence>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/billing/page.tsx":"\"use client\";\n﻿\"use client\";\n// Path: frontend/src/app/dashboard/billing/page.tsx\n\nimport { useState } from \"react\";\nimport { motion } from \"framer-motion\";\nimport { useTheme } from \"../../../components/layout/DashboardLayout\";\nimport { Check, Zap, Crown, ArrowUpRight, CreditCard, Receipt, ChevronRight, Shield, Sparkles } from \"lucide-react\";\nimport { useAuthStore } from \"../../../store/auth.store\";\nimport { useMutation } from \"@tanstack/react-query\";\nimport { api } from \"../../../lib/api\";\nimport toast from \"react-hot-toast\";\n\nconst V = { v900: \"#1A0D3D\", v700: \"#3D1C8A\", v600: \"#5428C8\", v500: \"#6B35E8\", v400: \"#8B5CF6\", v300: \"#A78BFA\", v200: \"#C4B5FD\", fuchsia: \"#C026D3\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\" },\n};\n\nconst PLANS = [\n  {\n    id: \"FREE\", name: \"Free\", price: { ngn: 0, gbp: 0, usd: 0 },\n    icon: Sparkles, color: \"#6B7280\",\n    features: [\"1 store\", \"20 products\", \"KIRO 10 msgs/day\", \"Basic analytics\", \"2% transaction fee\", \"Community support\"],\n    limit: true,\n  },\n  {\n    id: \"GROWTH\", name: \"Growth\", price: { ngn: 9500, gbp: 12, usd: 15 },\n    icon: Zap, color: V.v400,\n    features: [\"1 store\", \"Unlimited products\", \"Full KIRO access\", \"Advanced analytics\", \"Custom domain\", \"1.5% transaction fee\", \"Email support 24hr\", \"Coupons & flash sales\", \"Abandoned cart recovery\"],\n    popular: true,\n  },\n  {\n    id: \"PRO\", name: \"Pro\", price: { ngn: 25000, gbp: 35, usd: 45 },\n    icon: Crown, color: \"#F59E0B\",\n    features: [\"Unlimited stores\", \"Everything in Growth\", \"KIRO Pro intelligence\", \"WhatsApp commerce bot\", \"1% transaction fee\", \"Email campaigns\", \"Loyalty programme\", \"3 staff accounts\", \"API access\", \"Priority support 2hr\"],\n  },\n];\n\nconst CURRENCY_LABELS: Record<string, string> = { ngn: \"₦\", gbp: \"£\", usd: \"$\" };\n\nexport default function BillingPage() {\n  const { theme } = useTheme();\n  const t = theme === \"dark\" ? T.dark : T.light;\n  const { user } = useAuthStore();\n  const [billing, setBilling] = useState<\"monthly\" | \"annual\">(\"monthly\");\n  const [currency, setCurrency] = useState<\"ngn\" | \"gbp\" | \"usd\">(\"ngn\");\n  const currentPlan = user?.subscription?.plan || \"FREE\";\n\n  const upgradeMut = useMutation({\n    mutationFn: (planId: string) => api.post(\"/billing/upgrade\", { plan: planId, currency, billing }),\n    onSuccess: (res) => {\n      const url = res.data?.data?.authorizationUrl || res.data?.data?.url;\n      if (url) { window.location.href = url; }\n      else { toast.success(\"Plan updated!\"); }\n    },\n    onError: (e: any) => toast.error(e.response?.data?.message || \"Upgrade failed — backend offline\"),\n  });\n\n  const handleUpgrade = (planId: string) => {\n    if (planId === \"FREE\") return; // downgrade handled separately\n    upgradeMut.mutate(planId);\n  };\n\n  return (\n    <div style={{ maxWidth: 1100, margin: \"0 auto\" }}>\n      {/* Header */}\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}\n        style={{ display: \"flex\", alignItems: \"flex-start\", justifyContent: \"space-between\", gap: 16, marginBottom: 32 }}>\n        <div>\n          <h1 style={{ fontSize: 22, fontWeight: 800, letterSpacing: \"-0.03em\", color: t.text }}>Billing & Plans</h1>\n          <p style={{ fontSize: 13, color: t.muted, marginTop: 4 }}>Manage your subscription and payment details</p>\n        </div>\n        <div style={{ display: \"flex\", gap: 8 }}>\n          <button style={{ display: \"flex\", alignItems: \"center\", gap: 6, padding: \"9px 14px\", borderRadius: 11, border: `1px solid ${t.border}`, background: \"transparent\", cursor: \"pointer\", fontSize: 13, color: t.muted }}>\n            <Receipt size={13} /> View Invoices\n          </button>\n        </div>\n      </motion.div>\n\n      {/* Current plan banner */}\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}\n        style={{ padding: \"18px 22px\", borderRadius: 16, marginBottom: 28, background: \"rgba(107,53,232,0.08)\", border: \"1px solid rgba(107,53,232,0.2)\", display: \"flex\", alignItems: \"center\", gap: 14 }}>\n        <div style={{ width: 40, height: 40, borderRadius: 12, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", background: `linear-gradient(145deg, ${V.v500}, ${V.v900})`, boxShadow: \"0 4px 14px rgba(107,53,232,0.3)\" }}>\n          <Zap size={18} color=\"white\" />\n        </div>\n        <div style={{ flex: 1 }}>\n          <div style={{ fontSize: 14, fontWeight: 700, color: t.text }}>You're on the <span style={{ color: V.v300 }}>{currentPlan}</span> plan</div>\n          <div style={{ fontSize: 12, color: t.muted, marginTop: 2 }}>Upgrade anytime. No contracts. Cancel anytime.</div>\n        </div>\n        <div style={{ display: \"flex\", alignItems: \"center\", gap: 8 }}>\n          <Shield size={13} color={V.v400} />\n          <span style={{ fontSize: 12, color: V.v400 }}>Secured by Paystack</span>\n        </div>\n      </motion.div>\n\n      {/* Billing toggle + currency */}\n      <div className=\"flex flex-wrap items-center justify-center gap-3 mb-7\" style={{}}>\n        <div style={{ display: \"flex\", padding: 3, borderRadius: 12, background: t.card, border: `1px solid ${t.border}` }}>\n          {([\"monthly\", \"annual\"] as const).map(b => (\n            <button key={b} onClick={() => setBilling(b)}\n              style={{ padding: \"7px 20px\", borderRadius: 10, border: \"none\", cursor: \"pointer\", fontSize: 13, fontWeight: billing === b ? 600 : 400, background: billing === b ? (theme === \"dark\" ? \"rgba(107,53,232,0.25)\" : \"rgba(107,53,232,0.12)\") : \"transparent\", color: billing === b ? (theme === \"dark\" ? V.v200 : V.v600) : t.muted, transition: \"all 0.15s\" }}>\n              {b === \"monthly\" ? \"Monthly\" : \"Annual\"}{b === \"annual\" && <span style={{ marginLeft: 6, fontSize: 10, fontWeight: 700, padding: \"1px 5px\", borderRadius: 4, background: \"rgba(16,185,129,0.2)\", color: \"#10B981\" }}>-17%</span>}\n            </button>\n          ))}\n        </div>\n        <div style={{ display: \"flex\", padding: 3, borderRadius: 12, background: t.card, border: `1px solid ${t.border}` }}>\n          {([\"ngn\", \"gbp\", \"usd\"] as const).map(c => (\n            <button key={c} onClick={() => setCurrency(c)}\n              style={{ padding: \"7px 14px\", borderRadius: 10, border: \"none\", cursor: \"pointer\", fontSize: 13, fontWeight: currency === c ? 600 : 400, background: currency === c ? (theme === \"dark\" ? \"rgba(107,53,232,0.25)\" : \"rgba(107,53,232,0.12)\") : \"transparent\", color: currency === c ? (theme === \"dark\" ? V.v200 : V.v600) : t.muted, transition: \"all 0.15s\" }}>\n              {CURRENCY_LABELS[c]}{c.toUpperCase()}\n            </button>\n          ))}\n        </div>\n      </div>\n\n      {/* Plan cards */}\n      <div className=\"grid grid-cols-1 md:grid-cols-3 gap-4 mb-8\" style={{}}>\n        {PLANS.map((plan, i) => {\n          const Icon = plan.icon;\n          const isCurrent = currentPlan === plan.id;\n          const price = billing === \"annual\" ? Math.round(plan.price[currency] * 10) : plan.price[currency];\n          const isPopular = plan.popular;\n\n          return (\n            <motion.div key={plan.id} initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}\n              style={{ padding: 24, borderRadius: 20, position: \"relative\", overflow: \"hidden\", background: isPopular ? `linear-gradient(145deg, ${V.v900} 0%, #110D22 100%)` : t.card, border: `1px solid ${isPopular ? \"rgba(107,53,232,0.4)\" : isCurrent ? \"rgba(107,53,232,0.25)\" : t.border}`, boxShadow: isPopular ? \"0 8px 32px rgba(107,53,232,0.25)\" : theme === \"light\" ? \"0 1px 3px rgba(15,5,32,0.04), 0 4px 20px rgba(15,5,32,0.03)\" : \"none\" }}>\n\n              {/* Glow for popular */}\n              {isPopular && <div style={{ position: \"absolute\", top: -60, right: -60, width: 200, height: 200, borderRadius: \"50%\", background: \"radial-gradient(circle, rgba(107,53,232,0.2) 0%, transparent 70%)\", pointerEvents: \"none\" }} />}\n\n              {/* Popular badge */}\n              {isPopular && (\n                <div style={{ position: \"absolute\", top: 14, right: 14, fontFamily: \"'Syncopate', sans-serif\", fontSize: 7.5, fontWeight: 700, letterSpacing: \"0.1em\", padding: \"4px 8px\", borderRadius: 6, background: `linear-gradient(135deg, ${V.v500}, ${V.fuchsia})`, color: \"white\" }}>POPULAR</div>\n              )}\n\n              {/* Current badge */}\n              {isCurrent && !isPopular && (\n                <div style={{ position: \"absolute\", top: 14, right: 14, fontFamily: \"'Syncopate', sans-serif\", fontSize: 7.5, fontWeight: 700, letterSpacing: \"0.1em\", padding: \"4px 8px\", borderRadius: 6, background: \"rgba(16,185,129,0.15)\", color: \"#10B981\", border: \"1px solid rgba(16,185,129,0.25)\" }}>CURRENT</div>\n              )}\n\n              {/* Plan icon */}\n              <div style={{ width: 44, height: 44, borderRadius: 14, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", marginBottom: 16, background: `${plan.color}20`, border: `1px solid ${plan.color}30` }}>\n                <Icon size={20} color={plan.color} />\n              </div>\n\n              <div style={{ fontFamily: \"'Syncopate', sans-serif\", fontSize: 11, fontWeight: 700, letterSpacing: \"0.1em\", color: plan.color, marginBottom: 6 }}>{plan.name.toUpperCase()}</div>\n\n              <div style={{ marginBottom: 20 }}>\n                <span style={{ fontSize: 32, fontWeight: 800, letterSpacing: \"-0.04em\", color: isPopular ? \"#fff\" : t.text }}>\n                  {CURRENCY_LABELS[currency]}{price === 0 ? \"0\" : price.toLocaleString()}\n                </span>\n                {price > 0 && <span style={{ fontSize: 13, color: isPopular ? \"rgba(255,255,255,0.45)\" : t.muted }}>/mo</span>}\n                {price === 0 && <span style={{ fontSize: 13, color: isPopular ? \"rgba(255,255,255,0.45)\" : t.muted }}> forever</span>}\n                {billing === \"annual\" && price > 0 && <div style={{ fontSize: 11, color: \"#10B981\", marginTop: 3 }}>Billed annually · 2 months free</div>}\n              </div>\n\n              {/* CTA */}\n              <button\n                disabled={isCurrent || upgradeMut.isPending}\n                onClick={() => !isCurrent && handleUpgrade(plan.id)}\n                style={{ width: \"100%\", padding: \"11px\", borderRadius: 12, border: isCurrent ? `1px solid ${t.border}` : \"none\", cursor: isCurrent ? \"default\" : \"pointer\", fontSize: 13, fontWeight: 700, marginBottom: 20, background: isCurrent ? \"transparent\" : isPopular ? `linear-gradient(135deg, ${V.v500}, ${V.v700})` : `${plan.color}15`, color: isCurrent ? t.muted : isPopular ? \"white\" : plan.color, boxShadow: isPopular && !isCurrent ? \"0 4px 16px rgba(107,53,232,0.35)\" : \"none\", transition: \"all 0.15s\", opacity: upgradeMut.isPending ? 0.7 : 1 }}>\n                {upgradeMut.isPending && upgradeMut.variables === plan.id ? \"Opening Paystack...\" : isCurrent ? \"Current Plan\" : plan.id === \"FREE\" ? \"Downgrade\" : `Upgrade to ${plan.name}`}\n              </button>\n\n              {/* Features */}\n              <div style={{ display: \"flex\", flexDirection: \"column\", gap: 8 }}>\n                {plan.features.map(f => (\n                  <div key={f} style={{ display: \"flex\", alignItems: \"center\", gap: 8 }}>\n                    <div style={{ width: 16, height: 16, borderRadius: \"50%\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", background: `${plan.color}20`, flexShrink: 0 }}>\n                      <Check size={9} color={plan.color} />\n                    </div>\n                    <span style={{ fontSize: 12, color: isPopular ? \"rgba(255,255,255,0.7)\" : t.muted }}>{f}</span>\n                  </div>\n                ))}\n              </div>\n            </motion.div>\n          );\n        })}\n      </div>\n\n      {/* Payment method */}\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }}\n        style={{ padding: 20, borderRadius: 16, background: t.card, border: `1px solid ${t.border}`, display: \"flex\", alignItems: \"center\", gap: 14 }}>\n        <div style={{ width: 40, height: 40, borderRadius: 12, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", background: t.faint, border: `1px solid ${t.border}` }}>\n          <CreditCard size={18} color={t.muted} />\n        </div>\n        <div style={{ flex: 1 }}>\n          <div style={{ fontSize: 13, fontWeight: 600, color: t.text }}>No payment method added</div>\n          <div style={{ fontSize: 12, color: t.muted, marginTop: 2 }}>Add a card or bank account to upgrade your plan</div>\n        </div>\n        <button style={{ display: \"flex\", alignItems: \"center\", gap: 6, padding: \"8px 16px\", borderRadius: 10, border: \"none\", cursor: \"pointer\", background: `linear-gradient(135deg, ${V.v500}, ${V.v700})`, color: \"white\", fontSize: 13, fontWeight: 600, boxShadow: \"0 4px 12px rgba(107,53,232,0.3)\" }}>\n          Add Payment Method <ChevronRight size={13} />\n        </button>\n      </motion.div>\n    </div>\n  );\n}\n"};
let n=0;
for(const [rel,content] of Object.entries(files)){
  const p=rel.replace(/\//g,path.sep);
  fs.mkdirSync(path.dirname(p),{recursive:true});
  fs.writeFileSync(p,content,'utf8');
  console.log('OK',rel.split('/').slice(-2).join('/'));
  n++;
}
console.log('\nWritten:',n,'files');
try{
  execSync('git add .',{stdio:'inherit'});
  const st=execSync('git status --short',{encoding:'utf8'}).trim();
  if(st){
    execSync('git commit -m "fix: fully responsive dashboard — overview, products, settings, billing + mobile layout"',{stdio:'inherit'});
    execSync('git push origin main',{stdio:'inherit'});
    console.log('\nPushed. Vercel deploying.');
  } else { console.log('\nAlready up to date.'); }
}catch(e){console.log('Git:',e.message);}
